import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from '../api/axios'; // Using your specific axios instance

const PlanPage = () => {
    const [tasks, setTasks] = useState([]);
    const [loading, setLoading] = useState(true);
    const navigate = useNavigate();

    useEffect(() => {
        const fetchTasks = async () => {
            try {
                // Adjust this URL to match your backend exactly (e.g., /api/tasks or /tasks)
                const response = await axios.get('/tasks');
                setTasks(response.data);
            } catch (error) {
                console.error("Error fetching tasks:", error);
                // Fallback: Check localStorage if the backend fails during development
                const savedSchedule = localStorage.getItem('studyPulse_schedule');
                if (savedSchedule) {
                    setTasks(JSON.parse(savedSchedule));
                }
            } finally {
                setLoading(false);
            }
        };

        fetchTasks();
    }, []);

    // Calculate Progress
    const completedTasks = tasks.filter(t => t.status === 'completed').length;
    const totalTasks = tasks.length;
    const progressPercent = totalTasks > 0 ? (completedTasks / totalTasks) * 100 : 0;

    if (loading) return <div style={{ textAlign: 'center', marginTop: '50px' }}>Loading your plan...</div>;

    return (
        <div style={{ padding: '40px', maxWidth: '1000px', margin: '0 auto', fontFamily: 'Arial' }}>
            <h1 style={{ color: '#2c3e50' }}>Study Roadmap</h1>

            {/* Progress Bar Section */}
            <div style={{ marginBottom: '30px' }}>
                <div style={{ width: '100%', height: '15px', background: '#ecf0f1', borderRadius: '10px', overflow: 'hidden' }}>
                    <div 
                        style={{ 
                            width: `${progressPercent}%`, 
                            height: '100%', 
                            background: '#27ae60', 
                            transition: 'width 0.8s ease-in-out' 
                        }} 
                    />
                </div>
                <p style={{ textAlign: 'right', fontWeight: 'bold', marginTop: '5px' }}>
                    {Math.round(progressPercent)}% Syllabus Completed
                </p>
            </div>

            {/* Tasks Grid */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', gap: '20px' }}>
                {tasks.map((task, index) => (
                    <div 
                        key={task._id || index} 
                        onClick={() => {
                            // Only allow navigation if not already completed
                            if (task.status !== 'completed') {
                                navigate(`/study-room/${task._id || index}`);
                            }
                        }}
                        style={{ 
                            padding: '25px', 
                            borderRadius: '12px', 
                            border: '1px solid #ddd',
                            cursor: task.status === 'completed' ? 'default' : 'pointer',
                            background: task.status === 'completed' ? '#f0fff4' : '#fff',
                            boxShadow: '0 4px 6px rgba(0,0,0,0.05)',
                            transition: 'transform 0.2s',
                            position: 'relative'
                        }}
                        onMouseEnter={(e) => task.status !== 'completed' && (e.currentTarget.style.transform = 'translateY(-5px)')}
                        onMouseLeave={(e) => (e.currentTarget.style.transform = 'translateY(0)')}
                    >
                        <span style={{ fontSize: '12px', color: '#7f8c8d', textTransform: 'uppercase' }}>Day {index + 1}</span>
                        <h3 style={{ margin: '10px 0', color: '#2c3e50' }}>{task.title || task.topic}</h3>
                        
                        <div style={{ marginTop: '15px', display: 'flex', alignItems: 'center', gap: '10px' }}>
                            <span style={{ 
                                padding: '5px 10px', 
                                borderRadius: '20px', 
                                fontSize: '12px', 
                                fontWeight: 'bold',
                                color: task.status === 'completed' ? '#1b5e20' : '#e67e22',
                                background: task.status === 'completed' ? '#c8e6c9' : '#fef5e7'
                            }}>
                                {task.status === 'completed' ? 'COMPLETED' : 'PENDING'}
                            </span>
                            {task.status === 'completed' && <span style={{ fontSize: '18px' }}>✅</span>}
                        </div>
                    </div>
                ))}
            </div>

            {/* Reset Button */}
            <button 
                onClick={() => {
                    if(window.confirm("Start over? This deletes your current progress.")) {
                        localStorage.removeItem('studyPulse_schedule');
                        navigate('/dashboard');
                    }
                }}
                style={{ marginTop: '50px', background: 'none', border: 'none', color: '#e74c3c', cursor: 'pointer', textDecoration: 'underline' }}
            >
                Reset and Create New Plan
            </button>
        </div>
    );
};

export default PlanPage;
